// Extract URL from /learn command
const messageText = $input.first().json.message.text;
const chatId = $input.first().json.message.chat.id;
const userId = $input.first().json.message.from.id;

// Split the message: "/learn https://example.com"
const parts = messageText.trim().split(/\s+/);

// Check if URL was provided
if (parts.length < 2) {
  return {
    json: {
      error: true,
      chatId: chatId,
      errorMessage: "❌ Please provide a URL.\n\nUsage: /learn [url]\nExample: /learn https://example.com/article"
    }
  };
}

const url = parts[1];

// Basic URL validation
const urlPattern = /^https?:\/\/.+/i;
if (!urlPattern.test(url)) {
  return {
    json: {
      error: true,
      chatId: chatId,
      errorMessage: "❌ Invalid URL format.\n\nPlease provide a valid URL starting with http:// or https://"
    }
  };
}

// Success - return extracted data
return {
  json: {
    error: false,
    chatId: chatId,
    userId: userId,
    url: url,
    originalMessage: messageText
  }
};

