// Simple HTML to text extraction
const html = $input.first().json.data;
const url = $('Learn_ParseUrl').first().json.url;
const chatId = $('Learn_ParseUrl').first().json.chatId;
const userId = $('Learn_ParseUrl').first().json.userId;

// Remove script and style tags
let text = html.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
text = text.replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '');

// Remove HTML tags
text = text.replace(/<[^>]+>/g, ' ');

// Decode HTML entities
text = text.replace(/&nbsp;/g, ' ');
text = text.replace(/&amp;/g, '&');
text = text.replace(/&lt;/g, '<');
text = text.replace(/&gt;/g, '>');
text = text.replace(/&quot;/g, '"');

// Clean up whitespace
text = text.replace(/\s+/g, ' ').trim();

// Limit to first 8000 characters (for AI processing)
const content = text.substring(0, 8000);

// Try to extract title from first heading or use URL
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : url;

return {
  json: {
    url: url,
    title: title,
    content: content,
    chatId: chatId,
    userId: userId,
    contentLength: content.length
  }
};

// Parse Teacher AI response
const aiOutput = $input.first().json.output;
const previousData = $('Learn_GetMaterials_Parse').first().json;

// Extract the text from OpenAI response structure
let aiText = '';
if (Array.isArray(aiOutput) && aiOutput[0]?.content?.[0]?.text) {
  aiText = aiOutput[0].content[0].text;
} else {
  aiText = $input.first().json.message?.content || $input.first().json.text || '';
}

let summary;
try {
  // Remove markdown code blocks if present
  let jsonText = aiText.trim();

  // Check if wrapped in ```json ... ```
  if (jsonText.startsWith('```json')) {
    jsonText = jsonText.replace(/^```json\s*\n/, '').replace(/\n```$/, '');
  } else if (jsonText.startsWith('```')) {
    jsonText = jsonText.replace(/^```\s*\n/, '').replace(/\n```$/, '');
  }

  // Parse the cleaned JSON
  summary = JSON.parse(jsonText.trim());

} catch (error) {
  // Fallback if parsing fails
  console.error('JSON parse error:', error);
  summary = {
    title: previousData.title,
    overview: "Summary generation failed. Please try again.",
    keyPoints: [],
    mainConcepts: [],
    difficulty: "unknown",
    estimatedReadingTime: "N/A"
  };
}

// Generate unique ID for this material
const timestamp = Date.now();
const materialId = `LM-${timestamp}`;

// Prepare complete learning material object
return {
  json: {
    // Metadata
    id: materialId,
    userId: previousData.userId,
    chatId: previousData.chatId,
    url: previousData.url,
    addedDate: new Date().toISOString(),

    // Content
    title: summary.title || previousData.title,
    content: previousData.content,

    // AI-generated summary
    summary: {
      overview: summary.overview,
      keyPoints: summary.keyPoints || [],
      mainConcepts: summary.mainConcepts || [],
      difficulty: summary.difficulty || "intermediate",
      estimatedReadingTime: summary.estimatedReadingTime || "5 minutes"
    }
  }
};

// Format summary for Telegram display
const data = $input.first().json;
const summary = typeof data.summaryJSON === 'string' 
  ? JSON.parse(data.summaryJSON) 
  : data.summary;

// Build formatted message with Telegram Markdown
let message = `📚 *Learning Material Saved*\n\n`;
message += `*${data.title}*\n\n`;

// Overview
message += `📝 *Overview:*\n${summary.overview}\n\n`;

// Difficulty badge
const difficultyEmoji = {
  'beginner': '🟢',
  'intermediate': '🟡',
  'advanced': '🔴'
};
message += `${difficultyEmoji[summary.difficulty] || '⚪'} Difficulty: *${summary.difficulty}*\n`;
message += `⏱ Reading time: ${summary.estimatedReadingTime}\n\n`;

// Key Points
message += `🎯 *Key Points:*\n`;
summary.keyPoints.forEach((point, index) => {
  message += `${index + 1}. ${point}\n`;
});
message += `\n`;

// Main Concepts
message += `💡 *Main Concepts:*\n`;
summary.mainConcepts.forEach((concept, index) => {
  message += `• ${concept}\n`;
});
message += `\n`;

// Footer
message += `✅ Material saved! Use /quiz to test your knowledge.\n`;
message += `📎 ID: \`${data.id}\``;

return {
  json: {
    chatId: data.chatId,
    message: message,
    materialId: data.id
  }
};

const materials = $input.all();
const chatId = $('Telegram Trigger').first().json.message.chat.id;

const count = materials.length;

const keyboard = [];

materials.forEach(item => {
  const data = item.json;

  let difficulty = '⚪';
  try {
    const summary = typeof data.summaryJSON === 'string' 
      ? JSON.parse(data.summaryJSON) 
      : data.summary;

    const emojiMap = {
      'beginner': '🟢',
      'intermediate': '🟡',
      'advanced': '🔴'
    };
    difficulty = emojiMap[summary.difficulty] || '⚪';
  } catch (e) {}

  keyboard.push([{
    text: `${difficulty} ${data.title}`,
    callback_data: `quiz_${data.id}`
  }]);
});

keyboard.push([{
  text: '❌ Cancel',
  callback_data: 'quiz_cancel'
}]);

return [{
  json: {
    chat_id: String(chatId),
    text: `📚 Select a material to quiz on:\n\nYou have ${count} saved material(s).`,
    reply_markup: {
      inline_keyboard: keyboard
    }
  }
}];

const callbackData = $('MessageOrCallback').first().json.callback_query.data;
const userId = $('MessageOrCallback').first().json.callback_query.from.id;
const chatId = $('MessageOrCallback').first().json.callback_query.message.chat.id;

// Extract materialId from callback_data: "quiz_LM-1234567890"
const materialId = callbackData.replace('quiz_', '');

return {
  json: {
    materialId: materialId,
    userId: userId,
    chatId: chatId
  }
};

const aiOutput = $input.first().json.output;
const materialData = $('Quiz_LoadMaterial').first().json;
const chatId = $('Quiz_StartQuiz').first().json.chatId;
const userId = $('Quiz_StartQuiz').first().json.userId;
const materialId = $('Quiz_StartQuiz').first().json.materialId;

// Extract text from OpenAI response
let aiText = '';
if (Array.isArray(aiOutput) && aiOutput[0]?.content?.[0]?.text) {
  aiText = aiOutput[0].content[0].text;
} else {
  aiText = $input.first().json.message?.content || $input.first().json.text || '';
}

let questions;
try {
  let jsonText = aiText.trim();
  if (jsonText.startsWith('```json')) {
    jsonText = jsonText.replace(/^```json\s*\n/, '').replace(/\n```$/, '');
  } else if (jsonText.startsWith('```')) {
    jsonText = jsonText.replace(/^```\s*\n/, '').replace(/\n```$/, '');
  }
  questions = JSON.parse(jsonText.trim());
} catch (error) {
  throw new Error('Failed to parse quiz questions from AI response: ' + error.message);
}

if (!Array.isArray(questions) || questions.length < 5) {
  throw new Error('Expected 5 questions but got ' + (questions ? questions.length : 0));
}

// Take first 5 questions
questions = questions.slice(0, 5);

return {
  json: {
    materialId: materialId,
    userId: userId,
    chatId: chatId,
    title: materialData.title,
    quizJSON: JSON.stringify(questions),
    currentQuestion: 0,
    userAnswers: '[]',
    quizState: 'in_progress',
    quizScore: '',
    id: materialId,
    questions: questions
  }
};

const data = $('Quiz_ParseQuestions').first().json;
const questions = data.questions;
const questionIndex = 0;
const question = questions[questionIndex];
const chatId = data.chatId;
const materialId = data.materialId;

const text = `📝 Question ${questionIndex + 1}/5\n\n${question.question}\n\nA) ${question.options.A}\nB) ${question.options.B}\nC) ${question.options.C}\nD) ${question.options.D}`;

return { json: { chatId: String(chatId), text: text, materialId: materialId } };

const callbackData = $('MessageOrCallback').first().json.callback_query.data;
const chatId = $('MessageOrCallback').first().json.callback_query.message.chat.id;
const quizRow = $input.first().json;

// Extract answer and materialId from callback_data: "ans_LM-123_A"
const withoutPrefix = callbackData.replace('ans_', '');
const lastUnderscore = withoutPrefix.lastIndexOf('_');
const materialId = withoutPrefix.substring(0, lastUnderscore);
const userAnswer = withoutPrefix.substring(lastUnderscore + 1);

const questions = JSON.parse(quizRow.quizJSON);
const currentQ = parseInt(quizRow.currentQuestion);
const userAnswers = JSON.parse(quizRow.userAnswers || '[]');

const question = questions[currentQ];
const isCorrect = userAnswer === question.correctAnswer;

// Build feedback
let feedbackText = '';
if (isCorrect) {
  feedbackText = `✅ Correct!\n\nThe answer is ${question.correctAnswer}: ${question.options[question.correctAnswer]}`;
} else {
  feedbackText = `❌ Incorrect!\n\nYour answer: ${userAnswer}) ${question.options[userAnswer]}\nCorrect answer: ${question.correctAnswer}) ${question.options[question.correctAnswer]}\n\n💡 ${question.explanation}`;
}

// Update state
userAnswers.push({
  questionId: question.id,
  answer: userAnswer,
  correct: isCorrect
});

const nextQuestion = currentQ + 1;
const isComplete = nextQuestion >= 5;

let result = {
  materialId: materialId,
  chatId: chatId,
  feedbackText: feedbackText,
  currentQuestion: nextQuestion,
  userAnswers: JSON.stringify(userAnswers),
  quizState: isComplete ? 'completed' : 'in_progress',
  isComplete: isComplete,
  quizScore: '',
  id: materialId
};

if (!isComplete) {
  // Format next question
  const nextQ = questions[nextQuestion];
  result.nextText = `📝 Question ${nextQuestion + 1}/5\n\n${nextQ.question}\n\nA) ${nextQ.options.A}\nB) ${nextQ.options.B}\nC) ${nextQ.options.C}\nD) ${nextQ.options.D}`;
} else {
  // Calculate score
  const correctCount = userAnswers.filter(a => a.correct).length;
  const percentage = Math.round((correctCount / 5) * 100);
  result.quizScore = `${correctCount}`;

  // Build results message
  let resultsText = `📊 Quiz Results\n\n`;
  resultsText += `Material: ${quizRow.title}\n`;
  resultsText += `Score: ${correctCount}/5 (${percentage}%)\n\n`;

  userAnswers.forEach((ans, idx) => {
    const q = questions[idx];
    if (ans.correct) {
      resultsText += `${idx + 1}. ✅ ${q.question}\n   Your answer: ${ans.answer} ✓\n\n`;
    } else {
      resultsText += `${idx + 1}. ❌ ${q.question}\n   Your answer: ${ans.answer} ✗ (Correct: ${q.correctAnswer})\n   💡 ${q.explanation}\n\n`;
    }
  });

  if (percentage >= 80) {
    resultsText += `🎉 Excellent work! You've mastered this material!`;
  } else if (percentage >= 60) {
    resultsText += `👍 Good job! Review the incorrect answers to improve.`;
  } else {
    resultsText += `📚 Keep studying! Review the material and try again with /quiz.`;
  }

  result.resultsText = resultsText;
}

return { json: result };

const materialData = $input.first().json;
const chatId = $('Quiz_StartQuiz').first().json.chatId;
const userId = $('Quiz_StartQuiz').first().json.userId;
const materialId = $('Quiz_StartQuiz').first().json.materialId;

const hasQuiz = materialData.quizJSON && materialData.quizJSON.trim() !== '';
let needsGeneration = !hasQuiz;

let questions = [];
let currentQuestion = 0;
let userAnswers = '[]';
let quizState = 'in_progress';
let isResume = false;
let isCompleted = false;
let previousScore = '';

if (hasQuiz) {
  questions = JSON.parse(materialData.quizJSON);

  if (materialData.quizState === 'in_progress') {
    currentQuestion = parseInt(materialData.currentQuestion) || 0;
    userAnswers = materialData.userAnswers || '[]';
    isResume = true;

    if (currentQuestion >= questions.length) {
      currentQuestion = 0;
      userAnswers = '[]';
      isResume = false;
    }
  } else if (materialData.quizState === 'completed') {
    isCompleted = true;
    previousScore = materialData.quizScore || '0';
    currentQuestion = 0;
    userAnswers = '[]';
    isResume = false;
  } else {
    currentQuestion = 0;
    userAnswers = '[]';
    isResume = false;
  }
}

return {
  json: {
    needsGeneration: needsGeneration,
    isResume: isResume,
    isCompleted: isCompleted,
    previousScore: previousScore,
    materialId: materialId,
    chatId: chatId,
    userId: userId,
    title: materialData.title,
    id: materialId,
    quizJSON: materialData.quizJSON || '',
    currentQuestion: currentQuestion,
    userAnswers: userAnswers,
    quizState: quizState,
    quizScore: '',
    questions: questions
  }
};

const data = $('Quiz_CheckExisting').first().json;
const questions = data.questions;
const questionIndex = data.currentQuestion;
const question = questions[questionIndex];
const chatId = data.chatId;
const materialId = data.materialId;
const isResume = data.isResume;
const isCompleted = data.isCompleted;
const previousScore = data.previousScore;

let prefix = '';
if (isCompleted) {
  const score = parseInt(previousScore) || 0;
  if (score >= 5) {
    prefix = `🎉 Perfect score last time! You got ${score}/5 on this material. Can you repeat your success?\n\n🔄 Starting fresh quiz...\n\n`;
  } else {
    prefix = `📊 You scored ${score}/5 last time on this material. Try to beat your record!\n\n🔄 Starting fresh quiz...\n\n`;
  }
} else if (isResume) {
  prefix = '▶️ Resuming your quiz...\n\n';
} else {
  prefix = '🔄 Restarting quiz with saved questions...\n\n';
}

const text = `${prefix}📝 Question ${questionIndex + 1}/5\n\n${question.question}\n\nA) ${question.options.A}\nB) ${question.options.B}\nC) ${question.options.C}\nD) ${question.options.D}`;

return { json: { chatId: String(chatId), text: text, materialId: materialId } };
